#nullable enable // autogenerated

using System;
using System.Linq;

using MukioI18n;

using MVZ2.Audios;
using MVZ2.Cameras;
using MVZ2.GameContent.Difficulties;
using MVZ2.GlobalGames;
using MVZ2.Level.Components;
using MVZ2.Localization;
using MVZ2.Managers;
using MVZ2.Options;
using MVZ2.Saves;
using MVZ2.Scenes;

using MVZ2Logic.Level;
using MVZ2Logic.Options;

using PVZEngine;
using PVZEngine.Level;

using Tools;

using UnityEngine;

namespace MVZ2.Level
{
    public partial class LevelController : MonoBehaviour, ILevelController, IDisposable
    {
        private void Awake()
        {
            parts = new ILevelControllerPart[]
            {
                blueprintController,
                blueprintChooseController,
            };
            Awake_Collision();
            Awake_Model();
            Awake_Grids();
            Awake_Entities();
            Awake_Talk();
            Awake_Camera();
            Awake_UI(); // Awake_UI 要放在其他使用UIPreset的前面，防止获取到错误的Preset。
            Awake_HeldItem();
            Awake_ProgressBar();
            Awake_Tooltip();
            Awake_Dialogs();
            Awake_Tools();
            Awake_Artifacts();
            Awake_Blueprints();
            foreach (var controller in parts)
            {
                controller.Init(this);
            }

            OptionsManager.OnOptionChangedBool += OnOptionChangedBoolCallback;
            OptionsManager.OnKeybindingChanged += OnKeybindingChangedCallback;
            OptionsManager.OnKeybindingsReset += OnKeybindingsResetCallback;
        }
        private void ReadFromSerializable_Parts(SerializableLevelController seri)
        {
            foreach (var part in parts)
            {
                var seriPart = seri.parts.FirstOrDefault(p => p != null && p.id == part.ID);
                if (seriPart == null)
                {
                    Debug.LogWarning($"Could not find serialized LevelControllerPart data with id {part.ID}.");
                    continue;
                }
                part.LoadFromSerializable(seriPart);
            }
        }
        public void Dispose()
        {
            Music.SetVolume(1);
            Music.SetTrackWeight(0);
            if (level != null)
            {
                foreach (var component in level.GetComponents())
                {
                    if (component is IMVZ2LevelComponent comp)
                    {
                        comp.PostDispose();
                    }
                }
                level.StopAllLoopSounds();
                level.Dispose();
            }
            LevelManager.SetLevelController(null);

            OptionsManager.OnOptionChangedBool -= OnOptionChangedBoolCallback;
            OptionsManager.OnKeybindingChanged -= OnKeybindingChangedCallback;
            OptionsManager.OnKeybindingsReset -= OnKeybindingsResetCallback;
        }
        public void UpdateDifficulty()
        {
            if (level.CurrentFlag <= 0)
            {
                var difficulty = Options.GetDifficulty();
                // EXPAND(lunatic)难度限制：未通关过本关任意难度，则强制降为hard，并弹出提示  
                // 调试用户(debug/DESE107)或调试模式(编辑器)下解除该限制  
                // 无尽关卡(endless=true)无法通关，故也解除该限制  
                if (difficulty == VanillaDifficulties.lunatic
                    && Main.SaveManager.GetLevelDifficultyRecords(startStageID).Length <= 0
                    && !Main.DebugManager.CanUseDebugFeatures()
                    && !level.IsEndless())
                {
                    difficulty = VanillaDifficulties.hard;
                    var popup = Main.LanguageManager._(POPUP_DIFFICULTY_DOWNGRADED);
                    Main.Scene.ShowPopup(popup);
                }
                level.SetDifficulty(difficulty);
            }
            UpdateDifficultyName();
        }
        [TranslateMsg("EXPAND难度未通关时自动降级的提示")]
        public const string POPUP_DIFFICULTY_DOWNGRADED = "未通关，难度已自动调节为<color=yellow>EXP|困难</color>";
        public int GetCurrentFlag()
        {
            return level.CurrentFlag;
        }
        public LevelEngine GetEngine()
        {
            return level;
        }
        public void SetActive(bool active)
        {
            gameObject.SetActive(active);
        }
        public bool IsHPBarsUnlocked()
        {
            return isHPBarUnlocked;
        }
        public bool ShouldShowHPBars()
        {
            return Main.OptionsManager.IsHPBarEnabled() && IsHPBarsUnlocked();
        }

        private void OnOptionChangedBoolCallback(NamespaceID id, bool value)
        {
            if (id == LogicOptionItemID.showHotkeys)
            {
                UpdateHotkeyTexts();
            }
        }
        private void OnKeybindingChangedCallback(NamespaceID id, KeyCode code)
        {
            UpdateHotkeyTexts();
        }
        private void OnKeybindingsResetCallback()
        {
            UpdateHotkeyTexts();
        }

        #region 属性字段
        public GlobalGame Game => Main.Game;
        private MainManager Main => MainManager.Instance;
        private SaveManager Saves => Main.SaveManager;
        private MusicManager Music => Main.MusicManager;
        private LevelManager LevelManager => Main.LevelManager;
        private LanguageManager Localization => Main.LanguageManager;
        private ResourceManager Resources => Main.ResourceManager;
        private SoundManager Sounds => Main.SoundManager;
        private MainSceneController Scene => Main.Scene;
        private OptionsManager Options => Main.OptionsManager;
        private ShakeManager Shakes => Main.ShakeManager;
        private LevelEngine level = null!;
        private RandomGenerator rng = null!;

        private ILevelControllerPart[] parts = null!;
        private bool isHPBarUnlocked;
        #endregion
    }
}
